Rule.Source:
  
  	import sailpoint.object.Custom;
  	
	String 	CUSTOM_OBJECT_NAME_MDSTAFF_AMITA		= "Ascension-Custom-MDStaff-AMITA" ;
	
  	Custom custom=context.getObjectByName(Custom.class,CUSTOM_OBJECT_NAME_MDSTAFF_AMITA);
  	
  	List excludeIDNumbersList=custom.get("excludeIDNumbers");
  
	if (null == object.getAttribute("IDNumber") !=null && excludeIDNumbersList.contains(object.getAttribute("IDNumber"))) {  
		return null; 
	}   
	
    if (null == object.getAttribute("LastName") || null == object.getAttribute("FirstName") || null == object.getAttribute("DateOfBirth") || null == object.getAttribute("SSN")) {  
		return null; 
	}

    return object;
